import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";
import axios from "axios";

export default function Projectdetails() {
  const [showForm, setShowForm] = useState(false);
  const [projects, setProjects] = useState([]);

  const [formData, setFormData] = useState({
    projectName: "",
    location: "",
    budget: "",
    floors: "",
    startDate: "",
    endDate: "",
    description: "",
  });

  const today = new Date().toISOString().split("T")[0];

  // ✅ LOAD PROJECTS FROM LOCALSTORAGE WHEN PAGE LOADS
  useEffect(() => {
    const storedProjects =
      JSON.parse(localStorage.getItem("projects")) || [];
    setProjects(storedProjects);
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;

    if (name === "budget" && value > 50000000) return;
    if (name === "floors" && value > 30) return;

    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = () => {
    if (!formData.projectName) {
      alert("Project name required");
      return;
    }

    const updatedProjects = [...projects, formData];

    setProjects(updatedProjects);

    // ✅ SAVE TO LOCALSTORAGE
    localStorage.setItem("projects", JSON.stringify(updatedProjects));

    // Reset form
    setFormData({
      projectName: "",
      location: "",
      budget: "",
      floors: "",
      startDate: "",
      endDate: "",
      description: "",
    });

    setShowForm(false);
  };

  return (
    <div className="flex bg-gray-100 min-h-screen">
      <Sidebar />

      <div className="flex-1 flex flex-col">
        <Topbar />

        <div className="p-8">

          {!showForm && (
            <>
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h1 className="text-3xl font-bold">Project Details</h1>
                  <p className="text-gray-500">
                    Manage all construction projects
                  </p>
                </div>

                <button
                  onClick={() => setShowForm(true)}
                  className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-xl shadow"
                >
                  + Add New Project
                </button>
              </div>

              {projects.length === 0 && (
                <div className="bg-white rounded-2xl shadow flex flex-col items-center justify-center py-24 text-gray-500">
                  <div className="text-6xl mb-4">✖</div>
                  <p>No projects found. Add your first project.</p>
                </div>
              )}

              {projects.length > 0 && (
                <div className="grid grid-cols-3 gap-6">
                  {projects.map((project, index) => (
                    <div
                      key={index}
                      className="bg-white p-6 rounded-2xl shadow"
                    >
                      <h3 className="text-xl font-bold mb-2">
                        {project.projectName}
                      </h3>
                      <p className="text-gray-500 mb-1">
                        📍 {project.location}
                      </p>
                      <p className="mb-1">
                        💰 ₹{Number(project.budget).toLocaleString()}
                      </p>
                      <p className="mb-1">
                        🏢 Floors: {project.floors}
                      </p>
                      <p className="text-sm text-gray-500">
                        {project.startDate} → {project.endDate}
                      </p>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}

          {showForm && (
            <div className="bg-white p-8 rounded-2xl shadow">
              <h2 className="text-2xl font-semibold mb-6">
                Add New Project
              </h2>

              <div className="grid grid-cols-2 gap-6">

                <input
                  type="text"
                  name="projectName"
                  value={formData.projectName}
                  onChange={handleChange}
                  placeholder="Project Name"
                  className="w-full px-4 py-3 border rounded-xl"
                />

                <input
                  type="text"
                  name="location"
                  value={formData.location}
                  onChange={handleChange}
                  placeholder="Location"
                  className="w-full px-4 py-3 border rounded-xl"
                />

                <input
                  type="number"
                  name="budget"
                  value={formData.budget}
                  onChange={handleChange}
                  max="50000000"
                  placeholder="Budget (Max 5Cr)"
                  className="w-full px-4 py-3 border rounded-xl"
                />

                <input
                  type="number"
                  name="floors"
                  value={formData.floors}
                  onChange={handleChange}
                  min="1"
                  max="30"
                  placeholder="Floors (1-30)"
                  className="w-full px-4 py-3 border rounded-xl"
                />

                <input
                  type="date"
                  name="startDate"
                  value={formData.startDate}
                  onChange={handleChange}
                  max={today}
                  className="w-full px-4 py-3 border rounded-xl"
                />

                <input
                  type="date"
                  name="endDate"
                  value={formData.endDate}
                  onChange={handleChange}
                  min={formData.startDate}
                  className="w-full px-4 py-3 border rounded-xl"
                />

              </div>

              <textarea
                name="description"
                value={formData.description}
                onChange={handleChange}
                rows="3"
                placeholder="Project Description"
                className="w-full px-4 py-3 border rounded-xl mt-6"
              />

              <div className="mt-6 flex gap-4">
                <button
                  onClick={handleSubmit}
                  className="bg-orange-500 text-white px-6 py-3 rounded-xl"
                >
                  Add Project
                </button>

                <button
                  onClick={() => setShowForm(false)}
                  className="bg-gray-300 px-6 py-3 rounded-xl"
                >
                  Cancel
                </button>
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}
